  ['year', 'month', 'day', 'hour'].forEach((key) => {
    const p   = pillars[key];
    const col = document.createElement('div');
    col.className = \\\`bazi-pillar bazi-pillar--\\\${key}\\\`;

    if (!p || !p.stem) {
