    proj.supportingFactors.push({
      label: `Wu-Xing Dominanz: ${wxEl}`,
      value: ELEMENT_PERSONALITY[wxEl] || wxEl,
      source: 'api_aggregated',
      endpoint: '/api/azodiac/profile',
